    "iocs": "[\"192.168.1.1\",\"external-update-cdn.net\",\"DNS rebinding\",\"rule:2023766\",\"RFC1918-in-public-DNS\",\"TTL:1\",\"8.8.8.8\"]",
    "timeline": "[{\"time\":\"16:45:10\",\"event\":\"Browser/process on 192.168.56.101 initiates DNS query for external-update-cdn.net\"},{\"time\":\"16:45:20\",\"event\":\"Suricata [1:2023766:2]: DNS response from 8.8.8.8 returns RFC1918 address 192.168.1.1 for external-update-cdn.net\"},{\"time\":\"16:45:21\",\"event\":\"DNS rebinding TTL=1 forces immediate cache expiry; rebinding to internal IP confirmed\"},{\"time\":\"16:45:25\",\"event\":\"Browser JavaScript may now make cross-origin requests to 192.168.1.1 (default gateway)\"},{\"time\":\"16:46:00\",\"event\":\"HTTP requests to 192.168.1.1 (router admin interface) from 192.168.56.101 monitored\"}]",
