db.prepare(`CREATE TABLE IF NOT EXISTS labs (
  id INTEGER PRIMARY KEY AUTOINCREMENT,
  slug TEXT UNIQUE NOT NULL,
  title TEXT NOT NULL,
  description TEXT,
  difficulty TEXT,
  category TEXT,
  points INTEGER DEFAULT 100,
  alert_refs TEXT DEFAULT '[]',
  order_index INTEGER DEFAULT 0
)`).run();


// Add missing columns idempotently
try { db.prepare('ALTER TABLE labs ADD COLUMN alert_refs TEXT DEFAULT "[]"').run(); } catch(e) {}
try { db.prepare('ALTER TABLE labs ADD COLUMN is_visible INTEGER DEFAULT 1').run(); } catch(e) {}

const insertLab = db.prepare(`
  INSERT OR REPLACE INTO labs (slug,title,description,difficulty,category,points,alert_refs,order_index,is_visible)
  VALUES (?,?,?,?,?,?,?,?,?)`);
for (const l of labs) {
  insertLab.run(l.slug, l.title, l.description, l.difficulty, l.category, l.points,
                l.alert_refs || '[]', l.order_index, l.is_visible != null ? l.is_visible : 1);
}
